SELECT NVL(B.CONTRACT_NUM, '-') CONTRACT_NUM, NVL(SUB_LINK_NAME, '-') SUB_LINK_NAME, NVL(AD_NATION, '-') AD_NATION, NVL(DECODE(AD_NATION, '', '미등록', F_GET_KT_CODE_NM('PPS_CUSTOMER', 'AD_NATION', AD_NATION)), '-') AD_NATION_NM, NVL(SOC, '-') SOC, NVL((SELECT RATE_NM SERVICE_NM FROM MSP_RATE_MST WHERE RATE_CD = SOC and rownum = 1), '-') AS SERVICE_NM, NVL(FIRST_SOC, '-') FIRST_SOC, NVL((SELECT RATE_NM SERVICE_NM FROM MSP_RATE_MST WHERE RATE_CD = SOC and rownum = 1), '-') AS FIRST_SERVICE_NM, NVL(SUB_STATUS, '-') SUB_STATUS, NVL(F_GET_KT_CODE_NM('PPS_CUSTOMER', 'SUB_STATUS', SUB_STATUS), '-') AS SUB_STATUS_NM, NVL(TO_CHAR(ENTER_DATE, 'YYYY-MM-DD'), '-') AS ENTER_DATE, NVL(TO_CHAR(STATUS_STOP_DT, 'YYYY-MM-DD'), '-') AS STATUS_STOP_DT, NVL(TO_CHAR(STATUS_CANCEL_DT, 'YYYY-MM-DD'), '-') AS STATUS_CANCEL_DT, NVL(TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD'), '-') AS BASIC_EXPIRE, NVL(MODEL_NAME, '-') MODEL_NAME, NVL(USE_TERM, '0') USE_TERM, NVL(TO_CHAR(LAST_BASIC_CHG_DT, 'YYYY-MM-DD'), '-') AS LAST_BASIC_CHG_DT, NVL(AGENT_ID, '-') AGENT_ID, NVL(F_GET_AGENT_NM(AGENT_ID), '-') AGENT_NM, NVL(AGENT_SALE_ID, '-') AGENT_SALE_ID , NVL(F_GET_AGENT_NM(AGENT_SALE_ID), '-') AGENT_SALE_NM, B.BASIC_REMAINS, A.TRY_RCG_CNT, A.TRY_RCG_CHARGE, A.RCG_EDIT_CHARGE, A.RCG_FREE_CHARGE, A.RCG_PAY_CHARGE, A.RCG_FREE_CANCEL_CHARGE, A.RCG_PAY_CANCEL_CHARGE, A.TOT_RCG_CNT, A.TOT_RCG_CHARGE, A.RCG_CARD_CHARGE, A.RCG_CMS_CHARGE, A.RCG_VAC_CHARGE, A.RCG_POS_CHARGE, A.RCG_ETC_CHARGE, A.USE_CNT, A.USE_DUR, A.USE_CHARGE, A.USE_PKT, A.VOC_N_DUR, A.VOC_N_CHARGE, A.VOC_I_DUR, A.VOC_I_CHARGE, TOT_VOC_DUR, TOT_VOC_CHARGE, A.VID_N_DUR, A.VID_N_CHARGE, A.VID_I_DUR, A.VID_I_CHARGE, TOT_VID_DUR, TOT_VID_CHARGE, A.SMS_N_CNT, A.SMS_N_CHARGE, A.SMS_I_CNT, A.SMS_I_CHARGE, TOT_SMS_CNT, TOT_SMS_CHARGE, A.PKT_N_DUR, A.PKT_N_CHARGE, A.PKT_I_DUR, A.PKT_I_CHARGE, TOT_PKT_DUR, TOT_PKT_CHARGE, A.DAY_CNT, A.DAY_CHARGE, A.ETC_CNT, A.ETC_DUR, A.ETC_PKT, A.ETC_CHARGE, REAL_CHARGE, EXCELLENT_VAL FROM (SELECT /*+ INDEX_DESC(C PPS_STATS_CDR_ENTER_DT_IDX)*/ CONTRACT_NUM, SUM(TRY_RCG_CNT) TRY_RCG_CNT, SUM(TRY_RCG_CHARGE) TRY_RCG_CHARGE, SUM(RCG_EDIT_CHARGE) RCG_EDIT_CHARGE, SUM(RCG_FREE_CHARGE) RCG_FREE_CHARGE, SUM(RCG_PAY_CHARGE) RCG_PAY_CHARGE, SUM(RCG_FREE_CANCEL_CHARGE) RCG_FREE_CANCEL_CHARGE, SUM(RCG_PAY_CANCEL_CHARGE) RCG_PAY_CANCEL_CHARGE, SUM(TOT_RCG_CNT) TOT_RCG_CNT, SUM(TOT_RCG_CHARGE) TOT_RCG_CHARGE, SUM(RCG_CARD_CHARGE) RCG_CARD_CHARGE, SUM(RCG_CMS_CHARGE) RCG_CMS_CHARGE, SUM(RCG_VAC_CHARGE) RCG_VAC_CHARGE, SUM(RCG_POS_CHARGE) RCG_POS_CHARGE, SUM(RCG_ETC_CHARGE) RCG_ETC_CHARGE, SUM(USE_CNT) USE_CNT, SUM(USE_DUR) USE_DUR, SUM(USE_CHARGE) USE_CHARGE, SUM(USE_PKT) USE_PKT, SUM(VOC_N_DUR) VOC_N_DUR, SUM(VOC_N_CHARGE) VOC_N_CHARGE, SUM(VOC_I_DUR) VOC_I_DUR, SUM(VOC_I_CHARGE) VOC_I_CHARGE, SUM(VOC_N_DUR+VOC_I_DUR) AS TOT_VOC_DUR, SUM(VOC_N_CHARGE+VOC_I_CHARGE) AS TOT_VOC_CHARGE, SUM(VID_N_DUR) VID_N_DUR, SUM(VID_N_CHARGE) VID_N_CHARGE, SUM(VID_I_DUR) VID_I_DUR, SUM(VID_I_CHARGE) VID_I_CHARGE, SUM(VID_N_DUR+VID_I_DUR) AS TOT_VID_DUR, SUM(VID_N_CHARGE+VID_I_CHARGE) AS TOT_VID_CHARGE, SUM(SMS_N_CNT) SMS_N_CNT, SUM(SMS_N_CHARGE) SMS_N_CHARGE, SUM(SMS_I_CNT) SMS_I_CNT, SUM(SMS_I_CHARGE) SMS_I_CHARGE, SUM(SMS_N_CNT+SMS_I_CNT) AS TOT_SMS_CNT, SUM(SMS_N_CHARGE+SMS_I_CHARGE) AS TOT_SMS_CHARGE, SUM(PKT_N_DUR) PKT_N_DUR, SUM(PKT_N_CHARGE) PKT_N_CHARGE, SUM(PKT_I_DUR) PKT_I_DUR, SUM(PKT_I_CHARGE) PKT_I_CHARGE, SUM(PKT_N_DUR+PKT_I_DUR) AS TOT_PKT_DUR, SUM(PKT_N_CHARGE+PKT_I_CHARGE) AS TOT_PKT_CHARGE, SUM(DAY_CNT) DAY_CNT, SUM(DAY_CHARGE) DAY_CHARGE, SUM(ETC_CNT) ETC_CNT, SUM(ETC_DUR) ETC_DUR, SUM(ETC_PKT) ETC_PKT, SUM(ETC_CHARGE) ETC_CHARGE, SUM(USE_CHARGE - DAY_CHARGE) AS REAL_CHARGE, SUM(USE_CHARGE - DAY_CHARGE - RCG_FREE_CHARGE) AS EXCELLENT_VAL FROM PPS_STATS_CDR C WHERE 1=1
AND ENTER_DATE < last_day(to_date(#{searchDate}, 'yyyymm'))+1 AND ENTER_DATE >= add_months(to_date(#{searchDate}, 'yyyymm'), -3)
