SELECT /*+ INDEX_DESC(A PPS_RCG_IDX1) */ A.SEQ, A.SUBSCRIBER_NO, NVL(DECODE(A.CONTRACT_NUM, 0, '', A.CONTRACT_NUM),'') CONTRACT_NUM, NVL(REQ_SRC,'') REQ_SRC, NVL(REQ_TYPE,'') REQ_TYPE, NVL(RECHARGE_INFO,'') RECHARGE_INFO, NVL(RECHARGE_METHOD,'') RECHARGE_METHOD, NVL(AMOUNT,0) AMOUNT, NVL(IN_AMOUNT,0) IN_AMOUNT, NVL(KT_RES_CODE,'') KT_RES_CODE, NVL(TO_CHAR(KT_RES_DT, 'YYYY-MM-DD HH24:MI:SS'),'') KT_RES_DT, NVL(ADMIN_ID, '') ADMIN_ID, NVL(F_GET_ADMIN_NM(ADMIN_ID),'') ADMIN_NM, NVL(RECHARGE_AGENT,'') RECHARGE_AGENT, NVL(F_GET_AGENT_NM(RECHARGE_AGENT),'') RECHARGE_AGENT_NAME, NVL(CHG_TYPE,'') CHG_TYPE, NVL(F_GET_KT_CODE_NM('PPS_RCG','CHG_TYPE',CHG_TYPE),'') CHG_TYPE_NAME, NVL(CANCEL_FLAG,'') CANCEL_FLAG, NVL(TO_CHAR(CANCEL_DT,'YYYY-MM-DD'),'') CANCEL_DT, NVL(BASIC_REMAINS,0) BASIC_REMAINS, NVL(TO_CHAR(RECHARGE_DATE, 'YYYY-MM-DD HH24:MI:SS'),'') RECHARGE_DATE, DECODE(CANCEL_FLAG, 'N', DECODE(KT_RES_CODE, '0000', '취소', ''), '') CANCEL_BTN, NVL(TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD'),'') BASIC_EXPIRE, REMARK, FREE_FLAG, DECODE(FREE_FLAG,'N','판매', 'Y','수수료', '-') FREE_FLAG_NM , F_GET_AGENT_NM ( (SELECT AGENT_ID FROM PPS_CUSTOMER WHERE CONTRACT_NUM = A.CONTRACT_NUM ) ) OPEN_AGENT_NM, B.LST_COM_ACTV_DATE FROM PPS_RCG A ,MSP_JUO_SUB_INFO B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.RECHARGE_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
AND A.RECHARGE_DATE >= TO_DATE(#{searchDate}, 'YYYYMM') AND A.RECHARGE_DATE < add_months(TO_DATE(#{searchDate},'yyyymm'), 1)
AND SUBSTR(B.LST_COM_ACTV_DATE,0,6) = #{searchOpenDate}
AND (REQ_TYPE = 'CMS_RCG_VOICE' OR REQ_TYPE = 'CMS_RCG_DATA')
AND (REQ_TYPE = 'POS_RCG_VOICE' OR REQ_TYPE = 'POS_RCG_DATA')
AND RECHARGE_METHOD = #{searchRechargeMethod}

